export default properties;

export const northProperties = properties.filter(p => p.zone === 'North');
export const southProperties = properties.filter(p => p.zone === 'South');
export const eastProperties  = properties.filter(p => p.zone === 'East');

// Helper: find by id
export const findById = (id) => properties.find(p => p.id === id);

// Helper: search by name or location
export const search = (query) => {
  const q = query.toLowerCase();
  return properties.filter(p =>
    p.name.toLowerCase().includes(q) ||
    p.location.toLowerCase().includes(q)
  );
};